#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


   vec2 dither_uv = vUvOriginal*uTexSize.xy*texsize_noise_lq.zw + rand_frame.xy;
   vec3 rand = texture(sampler_noise_lq, dither_uv).xyz-0.5;

   d = uTexSize.zw*4;
   dx = GetBlur1(vUvOriginal + vec2(1,0)*d) - GetBlur1(vUvOriginal - vec2(1,0)*d);
   dy = GetBlur1(vUvOriginal + vec2(0,1)*d) - GetBlur1(vUvOriginal - vec2(0,1)*d);

   d = mix(vUvOriginal,vUv,1);
   uv_y = d - vec2(dx.y,dy.y)*uTexSize.zw*6;
   uv_z = d - vec2(dx.z,dy.z)*uTexSize.zw*6;


   ret.y = GetPixel(uv_y).y - 0.008 + (1-GetPixel(vUvOriginal).x)*0.018;
   ret.z = GetPixel(uv_z).z - 0.008 + (0+GetPixel(vUvOriginal).x)*0.018;

    ret.x = texture( sampler_fc_main, vUv+rand*uTexSize.zw*.5 ).x;
    ret.x += (ret.x - GetBlur3(vUv).x)*0.15 + rand*0.0042;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


// ***** Martin's ripples on water surface code, parameterized by Flexi *****

float h = 0.333;                      // height of the horizon
float cut_off = 0.333;              // cut off lower border
vec2 t = vec2(0.05,-0.025)*uTime;  // velocity
float strength = 0.025;


vec2 c = vUvOriginal-vec2(0.5,1-h);
float z = 3/c.y;
vec2 uv_water = vec2(c.x*z*h,z*h)*0.05+t;
int mask = (c.y>0);
uv_water = (texture(sampler_noise_hq,uv_water)-0.5)*mask;
vec2 uv_mirror = 1.0-abs(fract((c+vec2(0.5,1))*0.5)*2-1)+vec2(0,-cut_off);
uv_mirror =fract(uv_mirror-uv_water.xy*strength);

// ***** :)


/*** Flexis cleaned up bipolar moebius spiral code ***/

float cutoff = 0.95;
int n = 2; // number of arms per spiral, use negative for other direction
float s = 0.8; // zoom - keep close to n/2

   c = (vUv-0.5)*2*uAspect.wz;
   numerator = (c + vec2(q21,q22))*64;
   denominator = c + vec2(q23,q24);
   fraction = vec2( numerator.x*denominator.x + numerator.y*denominator.y,
                      numerator.y*denominator.x - numerator.x*denominator.y)/
                      (denominator.x*denominator.x + denominator.y*denominator.y);
   c = fraction-0.5;
   float1 ang_hq = n*atan(c.x,c.y);
   vec2 spiral = vec2(ang_hq*q25+q26,s*uAspect.w*log(length(c))+ang_hq*q25+q27);
   spiral = 0.5 + (0.5 - abs( fract( spiral * 0.5 ) * 2.0 - 1.0 ))*cutoff; // mirror

/**********************************************/

ret = GetBlur3(spiral).y-GetBlur2(spiral).y+GetPixel(spiral).y;
ret *= clamp01(1 - GetBlur1(vUv).x*2);
ret = mix(ret,vec3(0.5,0,1),GetPixel(vUv).x + (GetBlur3(vUv)-GetBlur2(vUv)).x);
ret = mix(ret,vec3(1,0.7,0),GetBlur2(uv_mirror).z*2 + GetPixel(uv_mirror).z) ;

//ret = GetPixel(vUv);

  fragColor = ret;
}
